document.addEventListener('DOMContentLoaded', () => {

	const burger = document.querySelector('.burger');
	const menuMob = document.querySelector('.menu-mob');
	const body = document.body;

	const closeTriggers = [
		'.menu-mob__close-btn',
		'.header__logo',
		'.nav__link',
		'.header__contacts-tel',
		'.header__contacts-mail',
		'.menu-mob__btn'
	];

	const openMenu = () => {
		body.classList.add('no-scroll');
		if (menuMob) {
			menuMob.classList.add('menu-mob--open');
		}
	};

	const closeMenu = () => {
		body.classList.remove('no-scroll');
		if (menuMob) {
			menuMob.classList.remove('menu-mob--open');
		}
	};

	if (burger) {
		burger.addEventListener('click', (e) => {
			e.stopPropagation();
			openMenu();
		});
	}

	if (menuMob) {
		menuMob.addEventListener('click', (e) => {
			const isClickInside = e.target.closest('.menu-mob__inner');
			if (!isClickInside) {
				closeMenu();
			}
		});
	}

	closeTriggers.forEach(selector => {
		const elements = document.querySelectorAll(selector);
		elements.forEach(el => {
			el.addEventListener('click', closeMenu);
		});
	});

	document.addEventListener('keydown', (e) => {
		if (e.key === 'Escape' && body.classList.contains('no-scroll')) {
			closeMenu();
		}
	});

	const cookieBtn = document.querySelector('.cookie__btn');
	const cookie = document.querySelector('.cookie');

	if (cookieBtn && cookie) {
		cookieBtn.addEventListener('click', () => {
			cookie.classList.add('cookie--hide');
		});
	}

	const modalBlock = document.querySelector('.modal__block');
	const closeBtn = document.querySelector('.close-btn--modal');

	const initForm = (form) => {

		const nameInput = form.querySelector('#name');
		const phoneInput = form.querySelector('#phone');
		const emailInput = form.querySelector('#email');
		const consentCheckbox = form.querySelector('[data-consent]');
		const submitBtn = form.querySelector('.form__submit');
		const fileInput = form.querySelector('#files');
		const fileBtn = form.querySelector('.form__file-btn');
		const fileListContainer = form.querySelector('.form__file-list');

		let selectedFiles = [];

		const clearForm = () => {
			if (nameInput) nameInput.value = '';
			if (phoneInput) phoneInput.value = '';
			if (emailInput) emailInput.value = '';

			const messageTextarea = form.querySelector('#message');
			if (messageTextarea) messageTextarea.value = '';

			const checkboxes = form.querySelectorAll('.form__checkbox input[type="checkbox"]');
			checkboxes.forEach(checkbox => {
				checkbox.checked = false;
			});

			selectedFiles = [];
			updateFileList();
			updateFileInput();

			if (submitBtn) submitBtn.disabled = true;
		};

		const updateFileList = () => {
			if (!fileListContainer) return;
			fileListContainer.innerHTML = '';

			selectedFiles.forEach((file, index) => {
				const fileDiv = document.createElement('div');
				fileDiv.className = 'form__file-item';
				fileDiv.innerHTML = `
					<span>${file.name}</span>
					<button type="button" class="form__file-remove" data-index="${index}">✕</button>
				`;

				const removeBtn = fileDiv.querySelector('.form__file-remove');
				removeBtn.addEventListener('click', (e) => {
					e.stopPropagation();
					e.preventDefault();
					selectedFiles.splice(index, 1);
					updateFileList();
					updateFileInput();
				});

				fileListContainer.appendChild(fileDiv);
			});
		};

		const updateFileInput = () => {
			if (!fileInput) return;
			const dataTransfer = new DataTransfer();
			selectedFiles.forEach(file => dataTransfer.items.add(file));
			fileInput.files = dataTransfer.files;
		};

		const setupFileUpload = () => {
			if (!fileBtn || !fileInput) return;

			fileBtn.addEventListener('click', () => {
				fileInput.click();
			});

			fileInput.addEventListener('change', (e) => {
				const newFiles = Array.from(e.target.files);

				if (selectedFiles.length + newFiles.length > 3) {
					alert('Можно загрузить не более 3 файлов');
					return;
				}

				selectedFiles.push(...newFiles);
				updateFileList();
				updateFileInput();
			});
		};

		const validateName = (value) => {
			if (!value.trim()) return 'Пожалуйста, введите ваше имя';
			if (value.trim().length < 2) return 'Имя должно содержать минимум 2 символа';
			return '';
		};

		const validatePhone = (value) => {
			const digits = value.replace(/\D/g, '');
			if (!digits) return 'Пожалуйста, введите номер телефона';
			if (digits.length !== 11) return 'Введите корректный номер телефона (11 цифр)';
			return '';
		};

		const validateEmail = (value) => {
			if (!value.trim()) return 'Пожалуйста, введите email';
			const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
			if (!emailRegex.test(value)) return 'Введите корректный email';
			return '';
		};

		const validateConsent = () => {
			if (!consentCheckbox || !consentCheckbox.checked) {
				return 'Необходимо дать согласие на обработку персональных данных';
			}
			return '';
		};

		const validateField = (fieldName, value) => {
			let error = '';
			switch (fieldName) {
				case 'name': error = validateName(value); break;
				case 'phone': error = validatePhone(value); break;
				case 'email': error = validateEmail(value); break;
				case 'consent': error = validateConsent(); break;
			}
			return !error;
		};

		const validateAll = () => {
			let isNameValid = true;
			let isPhoneValid = true;
			let isEmailValid = true;
			let isConsentValid = true;

			if (nameInput) isNameValid = validateField('name', nameInput.value);
			if (phoneInput) isPhoneValid = validateField('phone', phoneInput.value);
			if (emailInput) isEmailValid = validateField('email', emailInput.value);
			isConsentValid = validateField('consent');

			return isNameValid && isPhoneValid && isEmailValid && isConsentValid;
		};

		const updateSubmitButton = () => {
			if (submitBtn) {
				const isValid = validateAll();
				submitBtn.disabled = !isValid;
			}
		};

		const setupRealTimeValidation = () => {
			if (nameInput) {
				nameInput.addEventListener('blur', () => {
					validateField('name', nameInput.value);
					updateSubmitButton();
				});
				nameInput.addEventListener('input', () => {
					updateSubmitButton();
				});
			}

			if (phoneInput) {
				phoneInput.addEventListener('blur', () => {
					validateField('phone', phoneInput.value);
					updateSubmitButton();
				});
				phoneInput.addEventListener('input', () => {
					updateSubmitButton();
				});
			}

			if (emailInput) {
				emailInput.addEventListener('blur', () => {
					validateField('email', emailInput.value);
					updateSubmitButton();
				});
				emailInput.addEventListener('input', () => {
					updateSubmitButton();
				});
			}

			if (consentCheckbox) {
				consentCheckbox.addEventListener('change', () => {
					validateField('consent');
					updateSubmitButton();
				});
			}
		};

		const setupFormSubmit = () => {
			if (submitBtn) {
				submitBtn.addEventListener('click', function(e) {
					e.preventDefault();

					if (!validateAll()) {
						return;
					}

					body.classList.remove('modal-open__block-form');
					body.classList.add('modal-open__block-success');
					if (!body.classList.contains('modal-open')) {
						body.classList.add('modal-open');
					}
					clearForm();
				});
			}
		};

		if (phoneInput) {
			phoneInput.addEventListener('input', (e) => {
				let value = e.target.value.replace(/\D/g, '');
				if (value.length > 11) value = value.slice(0, 11);

				let formatted = '';
				if (value.length > 0) {
					formatted = '+7';
					if (value.length > 1) formatted += ' (' + value.slice(1, 4);
					if (value.length >= 4) formatted += ') ' + value.slice(4, 7);
					if (value.length >= 7) formatted += '-' + value.slice(7, 9);
					if (value.length >= 9) formatted += '-' + value.slice(9, 11);
				}
				e.target.value = formatted;
			});
		}

		setupFileUpload();
		setupRealTimeValidation();
		setupFormSubmit();
		updateSubmitButton();
	};

	const forms = document.querySelectorAll('.form');
	forms.forEach(form => {
		initForm(form);
	});

	const closeAllModals = () => {

		document.querySelectorAll('.form').forEach(form => {
			const inputs = form.querySelectorAll('input, textarea');
			inputs.forEach(input => {
				if (input.type !== 'checkbox') {
					input.value = '';
				} else {
					input.checked = false;
				}
			});
			const submitBtn = form.querySelector('.form__submit');
			if (submitBtn) submitBtn.disabled = true;

			const fileListContainer = form.querySelector('.form__file-list');
			if (fileListContainer) {
				fileListContainer.innerHTML = '';
			}
			const fileInput = form.querySelector('#files');
			if (fileInput) {
				fileInput.value = '';
			}
		});

		body.classList.remove('modal-open');
		body.classList.remove('modal-open__block-form');
		body.classList.remove('modal-open__block-success');
		body.classList.remove('modal-open__block-table--1');
		body.classList.remove('modal-open__block-table--2');
		body.classList.remove('modal-open__block-table--3');
		body.classList.remove('modal-open__block-table--4');
	};

	const formBtns = document.querySelectorAll('.btn-form-js');

	formBtns.forEach(btn => {
		btn.addEventListener('click', (e) => {
			e.stopPropagation();

			body.classList.remove('modal-open__block-table--1');
			body.classList.remove('modal-open__block-table--2');
			body.classList.remove('modal-open__block-table--3');
			body.classList.remove('modal-open__block-table--4');

			// Добавляем класс открытия формы
			body.classList.add('modal-open');
			body.classList.add('modal-open__block-form');
		});
	});

	if (closeBtn) {
		closeBtn.addEventListener('click', (e) => {
			e.stopPropagation();
			closeAllModals();
		});
	}

	document.addEventListener('keydown', (e) => {
		if (e.key === 'Escape') {
			closeAllModals();
		}
	});

	const addModalClasses = (tableNumber) => {

		body.classList.remove(
			'modal-open__block-table--1',
			'modal-open__block-table--2',
			'modal-open__block-table--3',
			'modal-open__block-table--4'
		);

		body.classList.add('modal-open', `modal-open__block-table--${tableNumber}`);
	};

	document.querySelectorAll('.btn-table--1-js').forEach(btn => {
		btn.addEventListener('click', () => addModalClasses(1));
	});

	document.querySelectorAll('.btn-table--2-js').forEach(btn => {
		btn.addEventListener('click', () => addModalClasses(2));
	});

	document.querySelectorAll('.btn-table--3-js').forEach(btn => {
		btn.addEventListener('click', () => addModalClasses(3));
	});

	document.querySelectorAll('.btn-table--4-js').forEach(btn => {
		btn.addEventListener('click', () => addModalClasses(4));
	});

	const radios = document.querySelectorAll('input[name="tab"]');
	const tabContent = document.querySelector('.tab__content');

	if (!tabContent) return;

	const updateTabContent = (selectedId) => {
		// Убираем все классы
		tabContent.classList.remove('tab__open-1', 'tab__open-2', 'tab__open-3');

		// Добавляем нужный класс
		if (selectedId === 'tab-1') {
			tabContent.classList.add('tab__open-1');
		} else if (selectedId === 'tab-2') {
			tabContent.classList.add('tab__open-2');
		} else if (selectedId === 'tab-3') {
			tabContent.classList.add('tab__open-3');
		}
	};

	radios.forEach(radio => {
		radio.addEventListener('change', () => {
			if (radio.checked) {
				updateTabContent(radio.id);
			}
		});
	});

	const checkedRadio = document.querySelector('input[name="tab"]:checked');
	if (checkedRadio) {
		updateTabContent(checkedRadio.id);
	}

	const tabBtns = document.querySelectorAll('.btn--tab');

	tabBtns.forEach(btn => {

		btn.setAttribute('tabindex', '0');
		btn.setAttribute('role', 'button');

		btn.addEventListener('keydown', (event) => {
			if (event.key === 'Enter') {
				event.preventDefault();
				event.stopPropagation();
				btn.click();
			}
		});
	});

	const closeButtons = document.querySelectorAll('.close-btn--modal');

	closeButtons.forEach(btn => {
		btn.addEventListener('click', (e) => {
			e.stopPropagation();
			document.body.classList.remove(
				'modal-open',
				'modal-open__block-form',
				'modal-open__block-success',
				'modal-open__block-table--1',
				'modal-open__block-table--2',
				'modal-open__block-table--3',
				'modal-open__block-table--4'
			);
		});
	});



	document.addEventListener('click', (e) => {
		const modalWrapper = document.querySelector('.modal__wrapper');
		const modal = document.querySelector('.modal');

		const classesToRemove = [
			'modal-open',
			'modal-open__block-form',
			'modal-open__block-success',
			'modal-open__block-table--1',
			'modal-open__block-table--2',
			'modal-open__block-table--3',
			'modal-open__block-table--4'
		];

		if (modalWrapper && e.target === modalWrapper) {
			document.body.classList.remove(...classesToRemove);
		}

		if (modal && e.target === modal) {
			document.body.classList.remove(...classesToRemove);
		}
	});


	const swiper = new Swiper('.swiper-1', {
		slidesPerView: 1,
		spaceBetween: 20,
		// loop: true,

		navigation: {
			nextEl: '.page-slider__btn--next',
			prevEl: '.page-slider__btn--prev',
		},

		effect: 'slide',
		speed: 800,
	});


	const swiper2 = new Swiper('.swiper-2', {
		slidesPerView: 1,
		slidesPerGroup: 1,
		spaceBetween: 20,

		navigation: {
			nextEl: '.page-slider__btn--next',
			prevEl: '.page-slider__btn--prev',
		},

		effect: 'slide',
		speed: 800,

		breakpoints: {
			747: {
				slidesPerView: 2,
				slidesPerGroup: 2,
			}
		},
	});

});